function toText(value) {
  if (value === null || value === undefined) return '';
  return String(value);
}

function normalizeBreaks(text) {
  return toText(text).replace(/\r\n/g, '\n').trim();
}

function extractComments(payload) {
  if (Array.isArray(payload?.comments)) return payload.comments;
  if (Array.isArray(payload?.data?.comments)) return payload.data.comments;
  if (Array.isArray(payload?.comment_response?.comments)) return payload.comment_response.comments;
  return [];
}

function extractCommentText(comment) {
  return normalizeBreaks(
    comment?.comment_text ??
    comment?.comment ??
    comment?.text ??
    comment?.text_content ??
    ''
  );
}

function extractCommentAuthor(comment) {
  return (
    comment?.user?.username ||
    comment?.user?.name ||
    comment?.user?.email ||
    'Unknown'
  );
}

function extractCommentDateIso(comment) {
  const raw =
    comment?.date ??
    comment?.date_created ??
    comment?.date_added ??
    null;

  if (raw === null || raw === undefined || raw === '') return null;

  const n = Number(raw);
  if (Number.isFinite(n)) return new Date(n).toISOString();

  const d = new Date(raw);
  if (!Number.isNaN(d.getTime())) return d.toISOString();

  return null;
}

function buildCommentsMarkdown(comments) {
  const rows = comments
    .map((comment) => {
      const text = extractCommentText(comment);
      if (!text) return null;

      const author = extractCommentAuthor(comment);
      const dateIso = extractCommentDateIso(comment);
      const header = `- **${author}**${dateIso ? ` (${dateIso})` : ''}`;
      const body = text.replace(/\n/g, '\n  ');

      return `${header}\n\n  ${body}`;
    })
    .filter(Boolean);

  if (!rows.length) return '';

  return `## Comments\n\n${rows.join('\n\n')}`;
}

const preparedCards = $('Prepare Task Work Items').all().map(item => item.json ?? {});
const commentItems = $input.all();

return commentItems.map((item, index) => {
  const base = preparedCards[index] ?? {};
  const payload = item.json ?? {};
  const comments = extractComments(payload);

  const existingDescription = normalizeBreaks(base.description ?? base.description_base ?? '');
  const commentsMd = buildCommentsMarkdown(comments);

  const mergedDescription = commentsMd
    ? (existingDescription ? `${existingDescription}\n\n${commentsMd}` : commentsMd)
    : existingDescription;

  return {
    json: {
      ...base,
      comments,
      description: mergedDescription,
    },
    pairedItem: item.pairedItem ?? { item: index },
  };
});

const cfg = $('Set Config').first().json;
const tasks = $('Normalize ClickUp Parent Tasks').all().map(item => item.json ?? {});

function normalizeStatusKey(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ');
}

function titleCase(value) {
  return String(value || '')
    .split(' ')
    .filter(Boolean)
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ') || 'Other';
}

let statusMap = [];
try {
  statusMap = JSON.parse(cfg.status_stack_map_json || '[]');
} catch (error) {
  throw new Error('status_stack_map_json is not valid JSON.');
}

const byKey = new Map();

for (const item of statusMap) {
  const key = normalizeStatusKey(item.status_key);
  if (!key) continue;
  byKey.set(key, {
    stack_key: key,
    stack_title: item.stack_title || titleCase(key),
    order: Number(item.order || 999),
  });
}

for (const task of tasks) {
  const key = normalizeStatusKey(task.stack_key || task.stack_title);
  if (!key) continue;
  if (!byKey.has(key)) {
    byKey.set(key, {
      stack_key: key,
      stack_title: task.stack_title || titleCase(key),
      order: Number(task.stack_order || 900),
    });
  }
}

return Array.from(byKey.values())
  .sort((a, b) => (a.order || 999) - (b.order || 999))
  .map(item => ({ json: item }));

const tasks = $('Normalize ClickUp Parent Tasks').all().map(item => item.json ?? {});
const stackItems = $('Deck - Get Stacks').all();
const board = $('Deck - Get Board After Labels').first().json ?? {};

function normalizeKey(value) {
  return String(value || '').trim().toLowerCase().replace(/\s+/g, ' ');
}
function extractStacks(items) {
  const out = [];
  for (const item of items) {
    const j = item.json ?? item ?? {};
    if (Array.isArray(j)) { out.push(...j); continue; }
    const nested = [j.stacks, j.data?.stacks, j.data, j.items, j.results].find(v => Array.isArray(v));
    if (nested) { out.push(...nested); continue; }
    if (j && typeof j === 'object' && j.id && j.title) out.push(j);
  }
  return out;
}

const stacks = extractStacks(stackItems);
if (!stacks.length) throw new Error('No Deck stacks were returned. Check board permissions, base URL, or Deck API path.');
const stackByTitle = new Map(stacks.map(stack => [normalizeKey(stack.title), stack]));
const labelByTitle = new Map((Array.isArray(board.labels) ? board.labels : []).map(label => [normalizeKey(label.title), label]));
const missingTitles = Array.from(new Set(tasks.map(task => task.stack_title).filter(title => !stackByTitle.has(normalizeKey(title)))));
if (missingTitles.length) throw new Error(`These Deck stacks were not found after creation: ${missingTitles.join(', ')}`);

const orderCounters = new Map();
const out = [];
for (const task of tasks) {
  const stack = stackByTitle.get(normalizeKey(task.stack_title));
  const currentOrder = (orderCounters.get(stack.id) || 0) + 1000;
  orderCounters.set(stack.id, currentOrder);
  out.push({
    json: {
      ...task,
      stack_id: stack.id,
      description: task.description || task.description_base || '',
      order: currentOrder,
      label_ids: (Array.isArray(task.deck_labels) ? task.deck_labels : [])
        .map(label => labelByTitle.get(normalizeKey(label.title))?.id)
        .filter(Boolean),
      label_titles: (Array.isArray(task.deck_labels) ? task.deck_labels : []).map(label => label.title),
    }
  });
}
return out;

const createdCardItems = $('Deck - Create Card').all();
const preparedCardItems = $('Append Comments To Task').all();
const labelAssignItems = $('Deck - Assign Label').all();
const attemptedCards = preparedCardItems.length;
const failedCards = createdCardItems.filter(item => item.json?.error || item.error || !item.json?.id).length;
const createdCards = createdCardItems.filter(item => item.json?.id).length;
const attemptedLabelAssignments = $('Prepare Label Assignments').all().length;
const failedLabelAssignments = labelAssignItems.filter(item => item.json?.error || item.error).length;
const successfulLabelAssignments = attemptedLabelAssignments - failedLabelAssignments;

let attemptedDoneMarks = 0;
let failedDoneMarks = 0;
let successfulDoneMarks = 0;
try {
  attemptedDoneMarks = $('Prepare Completed Card Updates').all().length;
  const doneItems = $('Deck - Mark Card Done').all();
  failedDoneMarks = doneItems.filter(item => item.json?.error || item.error).length;
  successfulDoneMarks = attemptedDoneMarks - failedDoneMarks;
} catch (e) {}

return [{
  json: {
    message: `Deck import finished. Parent tasks attempted ${attemptedCards}. Cards created ${createdCards}. Card failures ${failedCards}. Cards marked done attempted ${attemptedDoneMarks}. Cards marked done succeeded ${successfulDoneMarks}. Done-mark failures ${failedDoneMarks}. Label assignments attempted ${attemptedLabelAssignments}. Label assignments succeeded ${successfulLabelAssignments}. Label assignment failures ${failedLabelAssignments}.`,
    attempted_cards: attemptedCards,
    created_cards: createdCards,
    failed_cards: failedCards,
    attempted_done_marks: attemptedDoneMarks,
    successful_done_marks: successfulDoneMarks,
    failed_done_marks: failedDoneMarks,
    attempted_label_assignments: attemptedLabelAssignments,
    successful_label_assignments: successfulLabelAssignments,
    failed_label_assignments: failedLabelAssignments,
    board_id: $('Set Config').first().json.nextcloud_deck_board_id,
    clickup_source_id: $('Set Config').first().json.clickup_list_id,
  }
}];

const cfg = $('Set Config').first().json;
const inputItems = $input.all();
function extractTasks(itemJson) {
  if (!itemJson) return [];
  if (Array.isArray(itemJson)) return itemJson;
  const candidates = [itemJson.tasks, itemJson.data?.tasks, itemJson.data, itemJson.items, itemJson.results];
  return candidates.find(v => Array.isArray(v)) || [];
}
let actualListId = null;
let actualListName = null;
let visibleTaskCount = 0;
for (const item of inputItems) {
  const tasks = extractTasks(item.json ?? {});
  visibleTaskCount += tasks.length;
  for (const task of tasks) {
    const listId = task?.list?.id || task?.list_id || null;
    const listName = task?.list?.name || task?.list_name || null;
    if (listId) {
      actualListId = String(listId);
      actualListName = listName ? String(listName) : null;
      break;
    }
  }
  if (actualListId) break;
}
if (!actualListId) {
  const fallback = String(cfg.clickup_list_id || '').trim();
  if (/^\d+$/.test(fallback)) actualListId = fallback;
  else throw new Error('Could not resolve the real ClickUp home list id from the view results.');
}
return [{ json: { clickup_view_id: String(cfg.clickup_list_id || ''), clickup_actual_list_id: actualListId, clickup_actual_list_name: actualListName, visible_task_count: visibleTaskCount } }];

const cfg = $('Set Config').first().json;
const src = $input.first().json ?? {};
const maxPages = Math.max(1, Number(cfg.max_pages || 10));
const listId = String(src.clickup_actual_list_id || '').trim();
if (!listId) throw new Error('clickup_actual_list_id is missing.');
return Array.from({ length: maxPages }, (_, i) => ({
  json: {
    page: i,
    clickup_actual_list_id: listId,
    clickup_actual_list_name: src.clickup_actual_list_name || null,
    clickup_view_id: src.clickup_view_id || cfg.clickup_list_id || null,
  }
}));

const tasks = $('Normalize ClickUp Parent Tasks').all().map(item => item.json ?? {});
const byTitle = new Map();
function normalizeColor(value, fallback = '808080') {
  let color = String(value || fallback).trim().replace(/^#/, '').toUpperCase();
  if (/^[0-9A-F]{8}$/.test(color)) color = color.slice(2);
  if (!/^[0-9A-F]{6}$/.test(color)) color = fallback;
  return color;
}
for (const task of tasks) {
  for (const label of Array.isArray(task.deck_labels) ? task.deck_labels : []) {
    const title = String(label?.title || '').trim();
    if (!title) continue;
    if (!byTitle.has(title)) {
      byTitle.set(title, { title, color: normalizeColor(label?.color, '808080') });
    }
  }
}
return Array.from(byTitle.values()).map(label => ({ json: label }));

const createdCards = $input.all();
const preparedCards = $('Append Comments To Task').all();
const board = $('Deck - Get Board After Labels').first().json ?? {};

function normalizeKey(value) {
  return String(value || '').trim().toLowerCase().replace(/\s+/g, ' ');
}

const labelById = new Map((Array.isArray(board.labels) ? board.labels : []).map(label => [Number(label.id), label]));

const out = [];
for (const created of createdCards) {
  const card = created.json ?? {};
  if (card?.error || !card?.id) continue;

  const pairedIndex = created.pairedItem?.item ?? null;
  const source = (pairedIndex !== null && preparedCards[pairedIndex]) ? (preparedCards[pairedIndex].json ?? {}) : {};
  const labelIds = Array.isArray(source.label_ids) ? source.label_ids : [];
  const stackId = card.stackId || source.stack_id || null;

  for (const labelId of labelIds) {
    if (!stackId) continue;
    const label = labelById.get(Number(labelId));
    out.push({
      json: {
        task_id: source.task_id || null,
        card_id: card.id,
        stack_id: stackId,
        label_id: Number(labelId),
        label_title: label?.title || null,
      }
    });
  }
}
return out;

const createdCards = $input.all();
const sourceItems = $('Append Comments To Task').all();
const fallbackOwner = $('Set Config').first().json.nextcloud_username;

const out = [];

for (const created of createdCards) {
  const card = created.json ?? {};
  if (card?.error || !card?.id) continue;

  const pairedIndex = created.pairedItem?.item ?? null;
  const source = (pairedIndex !== null && sourceItems[pairedIndex])
    ? (sourceItems[pairedIndex].json ?? {})
    : {};

  if (!source.clickup_is_complete) continue;

  const owner =
    card.owner ||
    source.owner ||
    fallbackOwner;

  out.push({
    json: {
      board_id: Number($('Set Config').first().json.nextcloud_deck_board_id),
      stack_id: Number(card.stackId || source.stack_id),
      card_id: Number(card.id),
      title: source.title || card.title || '',
      description: source.description || '',
      order: Number(source.order || card.order || 999),
      duedate: source.duedate || null,
      done: source.clickup_done_at || new Date().toISOString(),
      owner,
      task_id: source.task_id || null,
    }
  });
}

return out;

