const cfg = $('Set Config - View').first().json;
const inputItems = $input.all();

function asArray(value) {
  return Array.isArray(value) ? value : [];
}
function pick(obj, keys, fallback = null) {
  for (const key of keys) {
    if (obj && obj[key] !== undefined && obj[key] !== null && obj[key] !== '') return obj[key];
  }
  return fallback;
}
function firstNonEmpty(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return null;
}
function normalizeStatusKey(value) {
  return String(value || '').trim().toLowerCase().replace(/\s+/g, ' ');
}
function titleCase(value) {
  return String(value || '')
    .split(' ')
    .filter(Boolean)
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ') || 'Other';
}
function truncate(value, maxLength) {
  const str = String(value || '');
  return str.length <= maxLength ? str : str.slice(0, Math.max(0, maxLength - 1)).trimEnd() + '…';
}
function toMs(value) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(value);
  if (!Number.isFinite(n) || n <= 0) return null;
  return n;
}
function toIso(value) {
  const ms = toMs(value);
  if (!ms) return null;
  const unixMs = ms > 9999999999 ? ms : ms * 1000;
  try {
    return new Date(unixMs).toISOString();
  } catch {
    return null;
  }
}
function namesFromUsers(users) {
  return asArray(users)
    .map(user => user?.username || user?.email || user?.initials || user?.id)
    .filter(Boolean)
    .join(', ');
}
function namesFromTags(tags) {
  return asArray(tags)
    .map(tag => tag?.name || tag?.tag || tag)
    .filter(Boolean)
    .join(', ');
}
function priorityText(priority) {
  if (!priority) return null;
  if (typeof priority === 'string') return priority;
  return priority.priority || priority.name || priority.orderindex || null;
}
function normalizeColor(value, fallback = '808080') {
  let color = String(value || fallback).trim().replace(/^#/, '').toUpperCase();
  if (/^[0-9A-F]{8}$/.test(color)) color = color.slice(2);
  if (!/^[0-9A-F]{6}$/.test(color)) color = fallback;
  return color;
}
function checklistMarkdown(checklists) {
  const groups = [];
  for (const checklist of asArray(checklists)) {
    const title = checklist?.name || checklist?.title || 'Checklist';
    const items = asArray(checklist?.items).map(item => {
      const label = item?.name || item?.label || item?.text || 'Item';
      const checked = item?.resolved || item?.checked || item?.completed || false;
      return `- [${checked ? 'x' : ' '}] ${label}`;
    });
    if (items.length) groups.push(`### ${title}\n` + items.join('\n'));
  }
  return groups.join('\n\n');
}
function getCustomField(task, fieldName) {
  return asArray(task.custom_fields).find(field => String(field?.name || '').trim().toLowerCase() === String(fieldName).trim().toLowerCase()) || null;
}
function getDropdownFieldInfo(field) {
  if (!field) return null;
  const raw = field.value;
  const options = asArray(field.type_config?.options);
  if (raw === null || raw === undefined || raw === '') return null;
  const match = options.find(option =>
    String(option?.id) === String(raw) ||
    String(option?.orderindex) === String(raw) ||
    Number(option?.orderindex) === Number(raw)
  );
  if (!match) return null;
  return {
    name: String(match.name || '').trim(),
    color: normalizeColor(match.color, '808080'),
  };
}
function getProgressToOkrText(field) {
  if (!field || !field.value) return null;
  const value = field.value;
  if (typeof value.percent_completed === 'number') return `${Math.round(value.percent_completed * 100)}%`;
  if (value.current !== null && value.current !== undefined && value.current !== '') return `${value.current}%`;
  return null;
}
function extractTasks(itemJson) {
  if (!itemJson) return [];
  if (Array.isArray(itemJson)) return itemJson;
  const candidates = [itemJson.tasks, itemJson.data?.tasks, itemJson.data, itemJson.items, itemJson.results];
  return candidates.find(v => Array.isArray(v)) || [];
}

let statusMap = [];
try {
  statusMap = JSON.parse(cfg.status_stack_map_json || '[]');
} catch (error) {
  throw new Error('status_stack_map_json is not valid JSON.');
}
const statusMapping = new Map(
  statusMap.map(item => [
    normalizeStatusKey(item.status_key),
    {
      stack_title: item.stack_title || titleCase(item.status_key),
      stack_order: Number(item.order || 999),
    }
  ])
);

const byId = new Map();
for (const item of inputItems) {
  const tasks = extractTasks(item.json ?? {});
  for (const task of tasks) {
    const id = String(task?.id || task?.task_id || '').trim();
    if (!id) continue;
    if (!byId.has(id)) byId.set(id, task);
  }
}

const allTasks = Array.from(byId.values());
const parentTasks = allTasks.filter(task => {
  const parentId = firstNonEmpty(task.parent, task.parent_id);
  return !(parentId && String(parentId).trim() !== '');
});

function buildSubtaskMarkdown(subtasks) {
  if (!subtasks.length) return null;
  const prefix = String(cfg.subtask_title_prefix || '↳ ');
  return subtasks.map(subtask => {
    const statusText = firstNonEmpty(subtask?.status?.status, subtask?.status?.name, subtask?.status, 'other');
    const priority = priorityText(subtask.priority);
    const dueDateIso = toIso(firstNonEmpty(subtask.due_date, subtask.duedate));
    const isDone = normalizeStatusKey(statusText) === 'complete' || subtask?.status?.type === 'closed' || !!firstNonEmpty(subtask.date_closed, subtask.done);
    const details = [
      statusText ? `status: ${statusText}` : null,
      priority ? `priority: ${priority}` : null,
      dueDateIso ? `due: ${dueDateIso}` : null
    ].filter(Boolean).join(' | ');
    return `- [${isDone ? 'x' : ' '}] ${prefix}${subtask.name || subtask.id}${details ? ` — ${details}` : ''}`;
  }).join('\n');
}

const out = [];
for (const task of parentTasks) {
  const taskId = String(task.id || task.task_id);
  const taskName = String(firstNonEmpty(task.name, task.task_name, `Task ${taskId}`)).trim();
  const rawStatus = firstNonEmpty(task?.status?.status, task?.status?.name, task?.status, 'other');
  const statusKey = normalizeStatusKey(rawStatus);
  const mappedStatus = statusMapping.get(statusKey) || {
    stack_title: titleCase(statusKey),
    stack_order: 900,
  };
  const createdAtMs = toMs(firstNonEmpty(task.date_created, task.created_at));
  const dueDateIso = toIso(firstNonEmpty(task.due_date, task.duedate));
  const startDateIso = toIso(firstNonEmpty(task.start_date));
  const doneAtIso = toIso(firstNonEmpty(task.date_closed, task.done));
  const isComplete = task?.status?.type === 'closed' || statusKey === 'complete' || !!doneAtIso;
  const nativeTags = namesFromTags(task.tags);
  const assignees = namesFromUsers(task.assignees);
  const priority = priorityText(task.priority);
  const checklistMd = checklistMarkdown(task.checklists);
  const descriptionMd = String(firstNonEmpty(task.markdown_description, task.description, task.text_content, '') || '');
  const clickupUrl = firstNonEmpty(task.url, `https://app.clickup.com/t/${taskId}`);
  const timeEstimateMs = toMs(firstNonEmpty(task.time_estimate));
  const timeSpentMs = toMs(firstNonEmpty(task.time_spent));
  const timeEstimateHours = timeEstimateMs ? (timeEstimateMs / 3600000).toFixed(2) : null;
  const timeSpentHours = timeSpentMs ? (timeSpentMs / 3600000).toFixed(2) : null;
  const okrInfo = getDropdownFieldInfo(getCustomField(task, 'OKR'));
  const progressInfo = getDropdownFieldInfo(getCustomField(task, 'Progress'));
  const progressToOkrText = getProgressToOkrText(getCustomField(task, 'Progress to OKR'));
  const deckLabels = [
    okrInfo?.name ? { title: `OKR: ${okrInfo.name}`, color: okrInfo.color } : null,
    progressInfo?.name ? { title: `Progress: ${progressInfo.name}`, color: progressInfo.color } : null,
    priority ? { title: `Priority: ${String(priority).trim().toLowerCase()}`, color: normalizeColor(task?.priority?.color, '808080') } : null,
    isComplete ? { title: 'Finished', color: '31CC7C' } : null,
  ].filter(Boolean);

  const subtasks = allTasks
    .filter(candidate => String(firstNonEmpty(candidate.parent, candidate.parent_id) || '') === taskId)
    .sort((a, b) => {
      const aMs = toMs(firstNonEmpty(a.date_created, a.created_at)) || 0;
      const bMs = toMs(firstNonEmpty(b.date_created, b.created_at)) || 0;
      if (aMs !== bMs) return aMs - bMs;
      return String(a.name || a.id).localeCompare(String(b.name || b.id));
    });
  const subtasksMd = buildSubtaskMarkdown(subtasks);

  const metaLines = [
    `- **ClickUp task ID:** \`${taskId}\``,
    `- **Status:** ${mappedStatus.stack_title}`,
    isComplete ? `- **Completed in ClickUp:** Yes` : null,
    doneAtIso ? `- **Completed at:** ${doneAtIso}` : null,
    priority ? `- **Priority:** ${priority}` : null,
    okrInfo?.name ? `- **OKR:** ${okrInfo.name}` : null,
    progressInfo?.name ? `- **Progress:** ${progressInfo.name}` : null,
    progressToOkrText ? `- **Progress to OKR:** ${progressToOkrText}` : null,
    assignees ? `- **Assignees:** ${assignees}` : null,
    nativeTags ? `- **Tags:** ${nativeTags}` : null,
    startDateIso ? `- **Start date:** ${startDateIso}` : null,
    dueDateIso ? `- **Due date:** ${dueDateIso}` : null,
    timeEstimateHours ? `- **Time estimate (h):** ${timeEstimateHours}` : null,
    timeSpentHours ? `- **Time spent (h):** ${timeSpentHours}` : null,
    clickupUrl ? `- **ClickUp URL:** ${clickupUrl}` : null,
  ].filter(Boolean);

  const sections = [
    `Imported once from ClickUp source \`${cfg.clickup_list_id}\`.`,
    '',
    ...metaLines,
    '',
    descriptionMd ? `## Description\n\n${descriptionMd}` : null,
    checklistMd ? `## Checklists\n\n${checklistMd}` : null,
    subtasksMd ? `## Subtasks\n\n${subtasksMd}` : null,
  ].filter(section => section !== null);

  const description = sections.join('\n');

  out.push({
    json: {
      task_id: taskId,
      task_name: taskName,
      stack_key: statusKey,
      stack_title: mappedStatus.stack_title,
      stack_order: mappedStatus.stack_order,
      title: truncate(taskName, 255),
      description,
      description_base: description,
      duedate: dueDateIso,
      created_at_ms: createdAtMs || 0,
      deck_labels: deckLabels,
      clickup_is_complete: isComplete,
      clickup_done_at: doneAtIso,
